"Here is a method in Java to convert a string to title case while handling exceptions for certain words:

```java
public class TitleCaseConverter {

    private static final List<String> EXCEPTION_WORDS = List.of("of", "the", "is", "and");

    public static String convertToTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        // Ensure the first character is capitalized
        if (input.length() > 0) {
            char firstChar = input.charAt(0);
            if (Character.isUpperCase(firstChar)) {
                return input;
            } else {
                input = Character.toString(firstChar).toUpperCase() + input.substring(1);
            }
        }

        // Convert the rest of the string to title case, except for exception words
        StringBuilder result = new StringBuilder();
        boolean isException = false;

        for (int i = 0; i < input.length(); i++) {
            char currentChar = input.charAt(i);

            if (i == 0) {
                result.append(currentChar);
                continue;
            }

            if (Character.isLetter(currentChar)) {
                if (isException) {
                    result.append(currentChar);
                    isException = false;
                } else {
                    if (ExceptionalWord.isExceptionWord(currentChar)) {
                        result.append(currentChar);
                        isException = true;
                    } else {
                        result.append(Character.toUpperCase(currentChar));
                    }
                }
            } else {
                result.append(currentChar);
            }
        }

        return result.toString();
    }

    // Helper method to check if a character is an exception word
    private static class ExceptionalWord {
        public static boolean isExceptionWord(char c) {
            return EXCEPTION_WORDS.contains(Character.toString(c));
        }
    }
}
```

